from cryptography.fernet import Fernet

def generate_key():
    return Fernet.generate_key()

def encrypt_credit_card(credit_card_number, key):
    fernet = Fernet(key)
    encrypted = fernet.encrypt(credit_card_number.encode())
    return encrypted

def decrypt_credit_card(encrypted_credit_card, key):
    fernet = Fernet(key)
    decrypted = fernet.decrypt(encrypted_credit_card).decode()
    return decrypted

